  const bootstrapToken = await regionalBootstrap.attest(attestation);

  // 3. CSR enrollment to KCA
  const csr = await crypto.generateCSR(keyPair.privateKey, {
    spiffeID: `spiffe://example.org/faas/aws/us-east-1/123456789012/my-function/${process.env.AWS_LAMBDA_REQUEST_ID}`,
    ttl: '24h',
    scope: 'faas'
  });

  const svid = await kca.issueCertificate(csr, bootstrapToken);

  // 4. Configure TLS with PQC hybrid
  const tlsConfig = {
    key: keyPair.privateKey,
    cert: svid.cert,
    ca: svid.chain,
    ciphers: ['TLS_AES_256_GCM_SHA384'],
    sigalgs: ['ecdsa_secp256r1_sha256', 'ml-dsa-44'],
    kexGroups: ['x25519', 'x25519mlkem768']
  };

  return { tlsConfig, identity: svid.svID };
}

