async function enrollDevice(deviceInfo, regionalBootstrap) {
  // Step 1: Attest to regional bootstrap service
  const attestation = await regionalBootstrap.attest({
    deviceId: deviceInfo.id,
    baselineHash: deviceInfo.baselineHash,
    hardwareNonce: await deviceInfo.tpmChallenge()
  });

  // Step 2: Generate CSR with SPIFFE ID and scope
  const csr = await createCSR({
    commonName: deviceInfo.serialNumber,
    spiffeID: `spiffe://retail.acme.com/store-${deviceInfo.storeId}/${deviceInfo.type}-${deviceInfo.id}`,
    scope: 'edge-retail',
    policyClaims: {
      storeId: deviceInfo.storeId,
      modelSignAllowed: deviceInfo.authorizedModels
    }
  });

  // Step 3: Enroll to central KCA
  const cert = await kca.enroll(csr, attestation.token);

  return { cert, expiresAt: Date.now() + 600000 };
}

async function renewOnReconnect(enrollment) {
  if (Date.now() >= enrollment.expiresAt - 60000) {
    const revocationStatus = await checkRevocation(enrollment.cert.serialNumber);
    if (revocationStatus.revoked) {
      throw new Error('Certificate revoked');
    }
    return enrollDevice(enrollment.deviceInfo, enrollment.bootstrap);
  }
  return enrollment;
}
