// Renewal on reconnect with exponential backoff
async function renewCertificate(cert, attempt = 1) {
  try {
    return await kca.renewCertificate(cert);
  } catch (err) {
    if (attempt < maxRetries) {
      await sleep(Math.min(1000 * 2 ** attempt, 30000));
      return renewCertificate(cert, attempt + 1);
    }
    throw err;
  }
}
